"""Run the full STL validation using the best available tool from the library.
Since we have no STL files to validate yet, let's first check what files exist
and then run validation on them."""
import os
import glob
import json
import math

# ── Improved validator (fixes inverted-normal bug) ──────────────────────────

def _cross(a, b):
    return (
        a[1]*b[2] - a[2]*b[1],
        a[2]*b[0] - a[0]*b[2],
        a[0]*b[1] - a[1]*b[0],
    )

def _sub(a, b):
    return (a[0]-b[0], a[1]-b[1], a[2]-b[2])

def _magnitude(v):
    return math.sqrt(v[0]**2 + v[1]**2 + v[2]**2)

def _dot(a, b):
    return a[0]*b[0] + a[1]*b[1] + a[2]*b[2]

def _normalize(v):
    m = _magnitude(v)
    if m == 0:
        return (0.0, 0.0, 0.0)
    return (v[0]/m, v[1]/m, v[2]/m)

def _triangle_area(v1, v2, v3):
    return 0.5 * _magnitude(_cross(_sub(v2, v1), _sub(v3, v1)))

def parse_stl_improved(path: str) -> dict:
    issues = []
    triangles = []  # list of (declared_normal, [v1, v2, v3])

    with open(path, "r", errors="replace") as fh:
        lines = fh.readlines()

    i = 0
    while i < len(lines):
        line = lines[i].strip()

        if line.startswith("facet normal"):
            parts = line.split()
            try:
                declared_normal = (float(parts[2]), float(parts[3]), float(parts[4]))
            except (IndexError, ValueError):
                issues.append(f"Malformed facet normal at line {i+1}")
                i += 1
                continue

            vertices = []
            i += 1
            if i < len(lines) and lines[i].strip() == "outer loop":
                i += 1
                for _ in range(3):
                    if i < len(lines):
                        vline = lines[i].strip()
                        if vline.startswith("vertex"):
                            vparts = vline.split()
                            try:
                                vertices.append((
                                    float(vparts[1]),
                                    float(vparts[2]),
                                    float(vparts[3])
                                ))
                            except (IndexError, ValueError):
                                issues.append(f"Malformed vertex at line {i+1}")
                        i += 1

            if len(vertices) == 3:
                triangles.append((declared_normal, vertices))
            else:
                issues.append(f"Incomplete triangle near line {i+1}")
            continue

        i += 1

    if not triangles:
        issues.append("No valid faces found")
        return {
            "valid": False,
            "triangle_count": 0,
            "surface_area": 0.0,
            "issues": issues,
        }

    # ── Manifold check ───────────────────────────────────────────────────────
    edge_count: dict = {}
    for _, verts in triangles:
        rounded = [tuple(round(x, 6) for x in v) for v in verts]
        for j in range(3):
            edge = tuple(sorted([rounded[j], rounded[(j+1) % 3]]))
            edge_count[edge] = edge_count.get(edge, 0) + 1

    open_edges = sum(1 for cnt in edge_count.values() if cnt == 1)
    if open_edges > 0:
        issues.append(f"Mesh has {open_edges} open edge(s) - not a closed solid")

    non_manifold_edges = sum(1 for cnt in edge_count.values() if cnt > 2)
    if non_manifold_edges > 0:
        issues.append(f"Mesh has {non_manifold_edges} non-manifold edge(s)")

    # ── Degenerate triangle check ────────────────────────────────────────────
    degenerate_count = 0
    for _, verts in triangles:
        area = _triangle_area(*verts)
        if area < 1e-12:
            degenerate_count += 1
    if degenerate_count > 0:
        issues.append(f"Mesh has {degenerate_count} degenerate (zero-area) triangle(s)")

    # ── Inverted normal check (THE FIX) ──────────────────────────────────────
    inverted_count = 0
    for declared_normal, verts in triangles:
        computed_cross = _cross(_sub(verts[1], verts[0]), _sub(verts[2], verts[0]))
        area = _magnitude(computed_cross)
        if area < 1e-12:
            continue  # degenerate, skip normal check
        computed_normal = _normalize(computed_cross)
        declared_n = _normalize(declared_normal)
        # If declared normal is zero vector, skip
        if _magnitude(declared_normal) < 1e-12:
            continue
        dot = _dot(computed_normal, declared_n)
        if dot < 0:  # pointing opposite direction
            inverted_count += 1
    if inverted_count > 0:
        issues.append(f"Mesh has {inverted_count} face(s) with inverted normals (winding-order mismatch)")

    surface_area = sum(_triangle_area(*verts) for _, verts in triangles)

    return {
        "valid": len(issues) == 0,
        "triangle_count": len(triangles),
        "surface_area": round(surface_area, 6),
        "issues": issues,
    }


# ── Find and validate all STL files ─────────────────────────────────────────
stl_files = sorted(glob.glob("*.stl") + glob.glob("**/*.stl", recursive=True))

if not stl_files:
    print("No STL files found in the working directory.")
    print("\nWorking directory contents:")
    for f in os.listdir("."):
        print(f"  {f}")
else:
    print(f"Found {len(stl_files)} STL file(s):")
    results = {}
    for stl_path in stl_files:
        result = parse_stl_improved(stl_path)
        results[stl_path] = result
        status = "PASS" if result["valid"] else "FAIL"
        print(f"\n[{status}] {stl_path}")
        print(f"  Triangles  : {result['triangle_count']}")
        print(f"  Surface area: {result['surface_area']}")
        if result["issues"]:
