    open_edges = sum(1 for cnt in edge_count.values() if cnt == 1)
    if open_edges > 0:
        issues.append(f"Mesh has {open_edges} open edge(s) - not a closed solid")

    # Check 2: Non-manifold edges
    non_manifold_edges = sum(1 for cnt in edge_count.values() if cnt > 2)
    if non_manifold_edges > 0:
        issues.append(f"Mesh has {non_manifold_edges} non-manifold edge(s)")

    # Check 3: Degenerate (zero-area) triangles
    degenerate_count = sum(
        1 for _, verts in triangles
        if _triangle_area(*verts) < 1e-12
    )
    if degenerate_count > 0:
        issues.append(f"Mesh has {degenerate_count} degenerate (zero-area) triangle(s)")

    # Check 4: Inverted normals (winding-order check) — THE FIX
    # In a valid STL, cross(v1-v0, v2-v0) must point in the same direction
    # as the declared face normal (dot product > 0).
    inverted_count = 0
    for declared_normal, verts in triangles:
        computed_cross = _cross(_sub(verts[1], verts[0]), _sub(verts[2], verts[0]))
        if _magnitude(computed_cross) < 1e-12:
            continue  # degenerate — already reported above
        if _magnitude(declared_normal) < 1e-12:
            continue  # zero declared normal — skip direction check
        computed_n = _normalize(computed_cross)
        declared_n = _normalize(declared_normal)
        if _dot(computed_n, declared_n) < 0:
            inverted_count += 1
    if inverted_count > 0:
        issues.append(
            f"Mesh has {inverted_count} face(s) with inverted normals "
            f"(declared normal disagrees with vertex winding order)"
        )

    surface_area = sum(_triangle_area(*verts) for _, verts in triangles)

    return {
        "valid": len(issues) == 0,
        "triangle_count": len(triangles),
        "surface_area": round(surface_area, 6),
        "issues": issues,
    }


