        print(json.dumps({"error": "usage: stl_validator_improved_final.py <file.stl> [file2.stl ...]"})) 
        sys.exit(1)

    results = {}
    for path in sys.argv[1:]:
        results[path] = parse_stl(path)

    if len(sys.argv) == 2:
